mapper.select:
SELECT
    (SELECT COUNT(*) FROM project_info WHERE del_flag = 0

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ) AS projectTotal,
    (SELECT COUNT(*) FROM project_info WHERE del_flag = 0 AND status = 0

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ) AS projectPending,
    (SELECT COUNT(*) FROM project_info WHERE del_flag = 0 AND status = 1

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ) AS projectRunning,
    (SELECT COUNT(*) FROM project_info WHERE del_flag = 0 AND status = 3

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ) AS projectClosed,
    (SELECT COUNT(*) FROM sys_user WHERE del_flag = 0

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ) AS userTotal,
    (SELECT COUNT(*) FROM project_fund_record WHERE del_flag = 0 AND status = 0

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ) AS fundPendingCount,
    IFNULL((SELECT SUM(amount) FROM project_fund_record WHERE del_flag = 0 AND status = 0

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ), 0) AS fundPendingAmount,
    IFNULL((SELECT SUM(amount) FROM project_fund_record WHERE del_flag = 0 AND status = 1

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ), 0) AS fundApprovedAmount,
    (SELECT COUNT(*) FROM project_achievement WHERE del_flag = 0

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ) AS achievementTotal,
    (SELECT COUNT(*) FROM project_achievement WHERE del_flag = 0 AND status = 0

        AND create_time >= #{dto.startDate}


        AND create_time <= CONCAT(#{dto.endDate}, ' 23:59:59')

    ) AS achievementPendingCount
